  ('dietitian-moex-08784', 'dietitian', 'dietitian-moex-098-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關燒傷患者補充蛋白質的處方敘述，下列何者錯誤？', '["成人建議量為總熱量的20%~25%", "兒童建議量為每公斤體重1.5~2公克", "可補充精胺酸以增加免疫力及促進傷口復原", "必須給予支鏈胺基酸（BCAA）以減少肝臟的負擔"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "95191f7f2b97", "answer_pdf_sha1": "63031e3acdd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08785', 'dietitian', 'dietitian-moex-098-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何營養素與預防或延緩老人眼部黃斑病變（age-related macular degeneration）最無關？', '["Lutein", "Zeaxanthin", "Folic acid", "Zinc"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "95191f7f2b97", "answer_pdf_sha1": "63031e3acdd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
